INSERT INTO `template` (`id`, `template_name`, `prompt`, `module`, `field_json`, `is_tone`, `created_at`, `updated_at`) VALUES
(1, 'title', 'Generate a comma-separated string of common leave reasons that employees may provide to their employers. Include both personal and professional reasons for taking leave, such only ##title## . Aim to generate a diverse range of leave reasons that can be used in different situations. Please provide a comprehensive and varied list of leave reasons that can help employers understand and accommodate their employees\' needs.', 'allowance', '{\"field\":[{\"label\":\"Allowance Title\",\"placeholder\":\"e.g.Medical Allowance, Bonus Allowance\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 0, '2025-05-01 16:15:36', '2025-05-01 16:15:36'),
(2, 'title', 'Generate a comma-separated string of common leave reasons that employees may provide to their employers. Include both personal and professional reasons for taking leave, such only ##title## . Aim to generate a diverse range of leave reasons that can be used in different situations. Please provide a comprehensive and varied list of leave reasons that can help employers understand and accommodate their employees\' needs.', 'commission', '{\"field\":[{\"label\":\"Commission Title\",\"placeholder\":\"e.g.Sales Commission, Bonus Commission\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 0, '2025-05-01 16:15:36', '2025-05-01 16:15:36'),
